        return NULL;

    npy_intp n = PyArray_DIM(weights_array, 0);
    const double *w = (const double *)PyArray_DATA(weights_array);

    double risk_squared = 0.0;

    if (PyArray_Check(cov_obj)) {
        PyArrayObject *cov_array = (PyArrayObject *)cov_obj;
        const double *cov = (const double *)PyArray_DATA(cov_array);
        for (npy_intp i = 0; i < n; i++) {
            const double *row = cov + i * n;
            double row_sum = 0.0;
            for (npy_intp j = 0; j < n; j++) {
                row_sum += row[j] * w[j];
            }
            risk_squared += w[i] * row_sum;
        }
    } else {
        // Treat cov as a sequence of sequences of Python floats.
        for (npy_intp i = 0; i < n; i++) {
            PyObject *row = PyList_Check(cov_obj)
                                ? PyList_GET_ITEM(cov_obj, i)
                                : PySequence_GetItem(cov_obj, i);
            if (row == NULL) return NULL;
            double row_sum = 0.0;
            if (PyList_Check(row)) {
                for (npy_intp j = 0; j < n; j++) {
                    PyObject *v = PyList_GET_ITEM(row, j);
                    row_sum += PyFloat_AS_DOUBLE(v) * w[j];
                }
