                for (npy_intp j = 0; j < n; j++) {
                    PyObject *v = PySequence_GetItem(row, j);
                    if (v == NULL) { if (!PyList_Check(cov_obj)) Py_DECREF(row); return NULL; }
                    row_sum += PyFloat_AsDouble(v) * w[j];
                    Py_DECREF(v);
                }
            }
            if (!PyList_Check(cov_obj)) Py_DECREF(row);
            risk_squared += w[i] * row_sum;
        }
        if (PyErr_Occurred()) return NULL;
    }

    return PyFloat_FromDouble(sqrt(risk_squared));
}

